<div class="wdl-cards"><?php if($data['query']->have_posts()): while($data['query']->have_posts()):$data['query']->the_post(); $u=get_post_meta(get_the_ID(),'_wdl_file_url',true); $category=wp_strip_all_tags(get_the_term_list(get_the_ID(),'wdl_document_category','',', ')); $format=strtoupper($data['helpers']->get_file_ext($u)); $version=get_post_meta(get_the_ID(),'_wdl_version',true);?><article class="wdl-document-card wdl-item" data-search="<?php echo esc_attr(strtolower(trim(get_the_title().' '.$category.' '.$format.' '.$version))); ?>"><?php echo $data['helpers']->get_thumb_or_icon(get_the_ID(),$u,'medium');?><h3><?php the_title();?></h3><p><?php echo esc_html(get_post_meta(get_the_ID(),'_wdl_card_description',true));?></p><div class="wdl-card-actions"><a class="wdl-button" href="<?php echo esc_url(get_permalink());?>">Открыть</a><?php if($u):?><a class="wdl-button wdl-button-download" href="<?php echo esc_url($u);?>" target="_blank" rel="noopener">Скачать</a><?php endif;?></div></article><?php endwhile; else: ?><div>Документы не найдены</div><?php endif;?></div>
